import{_ as o,C as r,o as d,c as n,ag as e,E as s,w as i,a as l}from"./chunks/framework.BZohXCq9.js";const P=JSON.parse('{"title":"Qué Vendes — Productos","description":"Agrega, edita y administra los productos que aparecen en tu landing","frontmatter":{"title":"Qué Vendes — Productos","description":"Agrega, edita y administra los productos que aparecen en tu landing"},"headers":[],"relativePath":"studio/seccion-productos.md","filePath":"studio/seccion-productos.md"}'),c={name:"studio/seccion-productos.md"};function u(p,t,g,h,m,b){const a=r("Warning");return d(),n("div",null,[t[1]||(t[1]=e('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>La sección de <strong>Productos</strong> dentro del tab <strong>Qué Vendes</strong> es donde agregas y administras todos los productos que se muestran en tu página web. Cada producto tiene foto, nombre, precio, badge opcional y estado activo/inactivo.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Qué Vendes</strong> (segundo ícono en el menú lateral, 🛒) → Sección <strong>Productos</strong> (parte superior del tab)</p><p>Verás un grid de tarjetas con tus productos actuales y un botón <strong>&quot;Agregar Producto&quot;</strong> azul. También se muestra el contador: <em>&quot;X de Y productos&quot;</em> según tu plan.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="lista-de-productos" tabindex="-1">Lista de productos <a class="header-anchor" href="#lista-de-productos" aria-label="Permalink to &quot;Lista de productos&quot;">​</a></h3><ul><li>Grid de tarjetas de productos (3 columnas en escritorio)</li><li>Cada tarjeta muestra: miniatura, nombre, precio (REF), badge y estado</li><li>Al pasar el mouse sobre una tarjeta aparecen las acciones: <strong>Editar</strong> y <strong>Eliminar</strong></li></ul><h3 id="crear-editar-un-producto" tabindex="-1">Crear / editar un producto <a class="header-anchor" href="#crear-editar-un-producto" aria-label="Permalink to &quot;Crear / editar un producto&quot;">​</a></h3><p>Al darle clic a <strong>&quot;Agregar Producto&quot;</strong> o <strong>Editar</strong>, se abre un modal con estos campos:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre</strong></td><td>✅ Sí</td><td>Nombre del producto</td></tr><tr><td><strong>Descripción</strong></td><td>No</td><td>Descripción corta del producto</td></tr><tr><td><strong>Precio USD</strong></td><td>✅ Sí</td><td>Precio en dólares (REF). Se convierte a Bs automáticamente según tasa BCV</td></tr><tr><td><strong>Imagen</strong></td><td>No</td><td>Foto del producto (máx 2MB, se convierte a WebP 800px)</td></tr><tr><td><strong>Activo</strong></td><td>—</td><td>Toggle para mostrar/ocultar en la landing</td></tr><tr><td><strong>Destacado</strong></td><td>—</td><td>Checkbox para marcar como destacado</td></tr><tr><td><strong>Badge</strong></td><td>No</td><td>Etiqueta visual: ⭐ Destacado, 🔥 Hot, ✨ New, 🎉 Promo</td></tr><tr><td><strong>Posición</strong></td><td>No</td><td>Orden en que aparece en el grid</td></tr></tbody></table><h3 id="en-la-landing-lo-que-ve-tu-cliente" tabindex="-1">En la landing (lo que ve tu cliente) <a class="header-anchor" href="#en-la-landing-lo-que-ve-tu-cliente" aria-label="Permalink to &quot;En la landing (lo que ve tu cliente)&quot;">​</a></h3><p>Los productos se muestran en un <strong>grid de 3 columnas</strong>:</p><ul><li>Se muestran los primeros 6 productos</li><li>Un botón <strong>&quot;Ver más&quot;</strong> carga 6 más (hasta el máximo de tu plan)</li><li>Cada producto muestra: foto, nombre, precio, badge (si tiene)</li><li>Los precios se muestran según el modo de moneda configurado (REF, Bs, ambos)</li></ul><h3 id="badges-disponibles" tabindex="-1">Badges disponibles <a class="header-anchor" href="#badges-disponibles" aria-label="Permalink to &quot;Badges disponibles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Badge</th><th>Ícono</th><th>Cuándo usarlo</th></tr></thead><tbody><tr><td><strong>Destacado</strong></td><td>⭐</td><td>Tu producto estrella</td></tr><tr><td><strong>Hot</strong></td><td>🔥</td><td>Producto muy vendido o tendencia</td></tr><tr><td><strong>New</strong></td><td>✨</td><td>Producto recién agregado</td></tr><tr><td><strong>Promo</strong></td><td>🎉</td><td>Producto en promoción u oferta</td></tr></tbody></table><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No maneja inventario ni stock — no cuenta cuántos quedan</li><li>No permite variantes (talla/color) — para eso usa SYNTIcat</li><li>No tiene carrito de compras — para eso usa SYNTIcat</li><li>No procesa pagos — el cliente te contacta por WhatsApp</li><li>No tiene categorías de productos — son todos en un grid plano</li><li>No tiene búsqueda ni filtros en la landing</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>Máximo de productos</td><td>20</td><td>50</td><td>Ilimitados</td></tr><tr><td>Fotos por producto</td><td>1</td><td>1</td><td>3 (slider)</td></tr><tr><td>Badges</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Destacado</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Orden personalizable</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table>',20)),s(a,null,{default:i(()=>[...t[0]||(t[0]=[l(' Cuando llegas al límite de productos de tu plan, el botón **"Agregar Producto"** se desactiva y muestra un mensaje indicando que necesitas un plan superior. ',-1)])]),_:1}),t[2]||(t[2]=e('<h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-tienda-natural-vida-verde-en-caracas" tabindex="-1">Caso: Tienda natural &quot;Vida Verde&quot; en Caracas <a class="header-anchor" href="#caso-tienda-natural-vida-verde-en-caracas" aria-label="Permalink to &quot;Caso: Tienda natural &quot;Vida Verde&quot; en Caracas&quot;">​</a></h3><p>Laura tiene una tienda de productos naturales con el plan Oportunidad (20 productos).</p><ol><li>Va a <strong>Qué Vendes → Productos</strong></li><li>Dale clic a <strong>&quot;Agregar Producto&quot;</strong></li><li>Llena: Nombre &quot;Miel de abejas pura&quot;, Precio &quot;8&quot;, sube una foto de la miel</li><li>Activa el badge <strong>✨ New</strong> porque acaba de llegar</li><li>Guarda → el producto aparece en su landing</li><li>Repite para sus 15 productos más vendidos</li><li>Reordena poniendo la miel en posición #1 (producto estrella)</li></ol><p>En la landing, sus clientes ven un grid con los 6 primeros productos. Le dan clic a &quot;Ver más&quot; para ver el resto. Cuando quieren comprar, le escriben por WhatsApp.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/productos-y-servicios.html">Productos y servicios</a> — Vista general del catálogo</li><li><a href="/studio/seccion-servicios.html">Qué Vendes — Servicios</a> — Cómo agregar servicios</li><li><a href="/shared/imagenes.html">Imágenes</a> — Cómo subir fotos optimizadas</li></ul>',7))])}const v=o(c,[["render",u]]);export{P as __pageData,v as default};
